#![no_std]
#![no_main]

use cortex_m_rt::entry;
use cortex_m_semihosting::{
    debug::{self, EXIT_SUCCESS},
    hprintln,
};
use panic_semihosting as _;

use generated::predict;

// One real CWRU faulty bearing window from the held-out test set
// (post-FFT, post-standardization). Generated by train.py.
include!("../../../demo_input.rs");

#[entry]
fn main() -> ! {
    hprintln!("Running CWRU bearing anomaly inference on Cortex-M4...");

    let output = predict(&SAMPLE);
    let predicted = output
        .iter()
        .enumerate()
        .max_by(|a, b| a.1.partial_cmp(b.1).unwrap())
        .unwrap()
        .0;

    let label = if predicted == 1 { "FAULTY" } else { "healthy" };
    hprintln!("Predicted class: {} ({})", predicted, label);
    hprintln!("Expected class:  {}", EXPECTED_CLASS);

    hprintln!("Logits:");
    for (i, val) in output.iter().enumerate() {
        hprintln!("  [{}] {:.4}", i, val);
    }

    debug::exit(EXIT_SUCCESS);
    loop {}
}
